-- ── Outline ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Outline is a fast, collaborative team knowledge base and wiki for internal documentation, available as a hosted cloud service or self-hosted from its open-source codebase.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted, open source) or $10/month for the hosted Starter cloud plan$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$New York, NY, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Outline Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Outline is an open-source team wiki and knowledge base. Compare 2026 pricing, features, self-hosting options, and alternatives like Notion and Confluence.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Outline is a team knowledge base and wiki application built for internal documentation, product specs, meeting notes, onboarding guides, and support answers. The commercial company behind it was founded at the start of 2020 in New York City, building on roughly three years of prior open-source development, and it describes itself as bootstrapped and profitable rather than venture-funded. Outline is distributed under a source-available open-source license on GitHub, so teams can self-host it for free on their own infrastructure, or use the official hosted cloud version run by the company. Its core differentiator versus general-purpose workspace tools like Notion is speed and a document-first, markdown-native editing experience: a real-time collaborative editor, instant full-text search, nested document collections, revision history, and a command-driven interface aimed specifically at engineering and product-minded teams rather than general note-taking. Outline supports single sign-on, granular team and group permissions, an API and webhooks, and 20-plus integrations including Slack, GitHub, and Figma embeds, plus AI-assisted question answering and document translation on its hosted plans. Pricing for the hosted cloud product is tiered by team size and feature set: a Starter plan for small teams (roughly $10 per month), a Team plan for growing teams (roughly $79 per month) that adds SSO and deeper integrations, a Business plan for larger organizations (roughly $249 per month) that adds API access, audit logs, and email support, and a custom Enterprise tier for teams larger than 200 users; every cloud plan includes a free trial, and self-hosting the open-source version remains free indefinitely aside from infrastructure costs. Outline's target users are software teams, startups, and product organizations that want a fast, developer-friendly internal wiki without the overhead of a heavier enterprise content platform. Its principal competitors include Notion, Confluence, GitBook, and Slab, with Outline most often chosen by technical teams that value markdown compatibility, self-hosting control, and a lightweight, keyboard-driven interface over the broader all-in-one workspace features of tools like Notion.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3';

