-- ── Outreach ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Outreach is an enterprise sales engagement and revenue execution platform used by large sales organizations to automate prospecting, manage deals, forecast pipeline, and coach reps with AI agents.$q$, short_description),
  pricing_model = COALESCE($q$Custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom (contact sales)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$1,001-5,000 employees$q$, company_size),
  headquarters = COALESCE($q$Seattle, WA, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Outreach Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Outreach is an enterprise AI sales engagement platform for prospecting, deals, and forecasting. See 2026 pricing, features, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Outreach is an enterprise sales engagement platform, now positioned as an agentic AI platform for revenue teams, founded in 2014 by Wes Hather, Gordon Hempton, Manny Medina, Belinda Prince, and Andrew Kinzer and headquartered in Seattle, Washington. Outreach became one of the category-defining companies in sales engagement, raising roughly $489 million across multiple funding rounds from investors including Mayfield, Spark Capital, and Trinity Ventures, and reaching a valuation of about $4.4 billion following a $200 million round; it employs over 1,500 people across offices in Seattle, Atlanta, New York, and San Francisco. The platform, originally built around automated multichannel sales sequences (email, calling, and social touches), has expanded into a broader revenue execution suite covering prospecting and pipeline generation, deal management and risk inspection, AI-assisted sales forecasting, conversation intelligence and rep coaching, and customer retention and expansion workflows. In 2025-2026 the company rebranded its site from outreach.io to outreach.ai and restructured its product around AI agents, including tools such as Outreach Omni (a conversational agent for cross-platform queries and actions), Agent Studio (a visual workflow builder for configuring AI agents), and a Meeting Prep Agent, alongside a consolidated Amplify pricing structure (Amplify Core, Amplify Plus, and Amplify Pro) that layers on features like real-time transcription, deal health scoring, and multi-currency forecasting at higher tiers. Outreach does not publish self-serve pricing; prospective customers must request a demo and receive a custom quote, reflecting its focus on mid-market and enterprise sales organizations rather than small teams. Its core competitors are Salesloft, HubSpot Sales Hub, Apollo.io, and Outplay, with Outreach generally regarded as one of the two dominant, enterprise-grade players (alongside Salesloft) in the sales engagement category, differentiated by its scale, AI agent investment, and depth of forecasting and deal-inspection functionality built for large, complex sales organizations. Outreach's customer base skews toward mid-market and enterprise revenue organizations with dedicated sales operations and revenue operations teams, since the platform's forecasting, coaching, and deal-inspection tools are built to manage complex, multi-stage pipelines across large rep headcounts rather than the simpler needs of a small sales team. The company has continued to expand beyond pure sales engagement into a fuller revenue execution category, adding modules for customer success and renewal risk in addition to its original prospecting and pipeline tools, which further distinguishes it from lighter-weight, prospecting-focused competitors like Outplay and Apollo.io.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7afd1993-2c5f-430d-bd16-ce044308f9b1';

