-- ── OWASP Dependency-Check ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OWASP Dependency-Check is a free, open-source software composition analysis tool that scans project dependencies and flags known publicly disclosed vulnerabilities (CVEs) using CPE matching.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Not applicable (open-source project maintained by volunteer contributors)$q$, company_size),
  headquarters = COALESCE($q$Not applicable (community-maintained project under the OWASP Foundation)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OWASP Dependency-Check Review 2026: Guide, Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OWASP Dependency-Check scans dependencies for known CVEs. Learn how this free, open-source SCA tool works, its features, and top alternatives in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OWASP Dependency-Check is a free, open-source software composition analysis (SCA) tool that scans a project's dependencies and attempts to identify publicly disclosed vulnerabilities within them. Development began around September 2012, making it one of the earliest dedicated SCA tools in the application security space, and it was created and led for many years by Jeremy Long under the OWASP Foundation, the nonprofit best known for the OWASP Top 10 web application security risks list. The tool works primarily by generating evidence about each dependency (such as file hashes, embedded metadata, and package identifiers), mapping that evidence to Common Platform Enumeration (CPE) identifiers, and then cross-referencing those CPEs against the National Vulnerability Database (NVD) to surface associated Common Vulnerabilities and Exposures (CVE) entries, producing a report of known-vulnerable components with severity scores. It is distributed under the Apache License 2.0 and ships as a command-line tool along with plugins for Maven, Gradle, and Ant, plus integrations for CI/CD systems such as Jenkins, GitHub Actions, and Azure DevOps; it also leverages ecosystem-specific vulnerability sources such as the NPM Audit API, OSS Index, RetireJS, and Bundler Audit to extend coverage beyond Java into JavaScript, Ruby, and other languages. Its primary GitHub home moved from the original jeremylong/DependencyCheck repository to a dedicated dependency-check organization to support continued community-driven maintenance. Dependency-Check is used by application security engineers, DevSecOps teams, and individual developers who want a free, self-hosted way to catch known-vulnerable open-source libraries in CI pipelines before they reach production, and it is designated an OWASP Flagship project reflecting its maturity and adoption. Its closest free/open-source alternative is OWASP Dependency-Track, which consumes Dependency-Check-style output for continuous monitoring, while commercial competitors in the broader SCA space include Snyk, Mend (formerly WhiteSource), and GitHub's native Dependabot, with Dependency-Check differentiating itself as a fully free, locally runnable scanner rather than a hosted SaaS platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4e30e978-262d-4a83-b746-96ea2a1f37ae';

