-- ── OWASP ZAP ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OWASP ZAP (Zed Attack Proxy) is a free, open-source dynamic application security testing tool that acts as an intercepting proxy to actively and passively scan running web applications for vulnerabilities.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Not applicable (open-source project; core team is now supported by Checkmarx)$q$, company_size),
  headquarters = COALESCE($q$Not applicable (community-governed open-source project)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OWASP ZAP Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OWASP ZAP is a free, open-source web app security scanner and proxy for penetration testing. See 2026 features, use cases, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OWASP ZAP, short for Zed Attack Proxy, is a free and open-source dynamic application security testing (DAST) tool used to find security vulnerabilities in running web applications and APIs. It was founded in 2010 by Simon Bennetts as an OWASP project, forked originally from the Paros proxy developed by Chinotec Technologies, and its first public release was announced in September 2010; it grew over the following decade into the most widely used open-source web application security scanner in the world and an OWASP Flagship project. Unlike a software composition analysis tool, ZAP works by sitting as an intercepting proxy between a browser (or automated client) and a target web application, allowing it to passively observe traffic and actively send crafted attack payloads to probe for issues such as SQL injection, cross-site scripting, and insecure configurations, then report the findings with actionable detail. In 2023, the ZAP project left the OWASP Foundation and moved under the Linux Foundation's Software Security umbrella to secure additional funding and resources, and in 2024 its core team joined the security vendor Checkmarx, with the project rebranded as ZAP by Checkmarx; it remains free, open source under the Apache License 2.0, and community-governed, with Checkmarx providing sponsorship and dedicated engineering resources rather than converting it into a paid product. ZAP's feature set includes an automated active and passive scanner, a traffic-intercepting proxy for manual testing, fuzzing tools, a scripting and automation framework for integrating scans into CI/CD pipelines, and a marketplace of community-built add-ons that extend its capabilities. It is used by penetration testers, application security engineers, and developers who want to run automated or manual DAST scans against staging or test environments without paying for a commercial scanner. Its main alternatives and competitors include Burp Suite (particularly Burp Suite Professional), Acunetix, Invicti (formerly Netsparker), and Nikto, with ZAP differentiating itself as the leading free, fully open-source option in a category where most comparable scanners are commercial products.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '26fa7763-662c-4590-abb7-062fe17b309e';

