INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Quiz and calculator builder$q$, $q$Drag-and-drop editor for building branching quizzes, assessments, and multi-variable calculators without code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Lead scoring$q$, $q$Assigns point values to user answers so leads can be automatically qualified and segmented.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Conditional logic$q$, $q$Shows or hides questions and results dynamically based on prior answers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Templates and layouts$q$, $q$Library of pre-built industry templates and layout styles to speed up content creation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$A/B testing$q$, $q$Tests variations of interactive content to optimize completion and conversion rates.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Native integrations$q$, $q$Connects to CRM, email marketing, and ad platforms, plus Zapier for broader automation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Analytics dashboard$q$, $q$Tracks views, completion rates, and drop-off points for every piece of content.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$White-label branding$q$, $q$Removes Outgrow branding and applies custom domains and colors on higher-tier plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$No-code builder makes it accessible to marketers without developer support$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Strong lead scoring and qualification features tailored to demand generation$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Wide range of content types beyond quizzes, including calculators and chatbots$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Free plan available for testing basic forms and surveys before committing to a paid tier$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Large template library across many industries$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Pricing rises quickly once lead volume or content-type needs increase$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Interface and logic builder can feel complex for first-time users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Design customization is more limited than dedicated form or landing page tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Enterprise pricing is not published and requires a sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Some advanced features are gated behind higher tiers even for small teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$What is Outgrow used for?$q$, $q$Outgrow is used to build interactive content, such as quizzes, calculators, assessments, and chatbots, that capture and qualify leads by engaging website visitors instead of relying on static forms.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Does Outgrow have a free plan?$q$, $q$Yes, Outgrow offers a free plan limited to basic forms and surveys with a capped number of leads per year; more advanced content types require a paid plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$How much does Outgrow cost?$q$, $q$Paid plans start around $22 per month billed monthly (about $14 per month billed annually) and scale up through Freelancer, Essentials, and Business tiers, with custom Enterprise pricing for larger teams.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Does Outgrow integrate with my CRM?$q$, $q$Outgrow offers native integrations with popular marketing and CRM tools such as HubSpot, Mailchimp, and Marketo, plus a Zapier connection for broader automation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Who is Outgrow best suited for?$q$, $q$Outgrow is best suited for marketing teams, growth marketers, agencies, and B2B companies that want to generate and qualify leads through interactive content rather than static landing pages.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$What are the main alternatives to Outgrow?$q$, $q$Common alternatives include Typeform, Involve.me, ConvertFlow, and Jotform, though Outgrow differentiates itself with lead scoring and calculator-style logic aimed at demand generation.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Can Outgrow content be embedded on any website?$q$, $q$Yes, Outgrow content can be embedded on most websites via code snippet, or shared as a standalone hosted link.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Does Outgrow support A/B testing?$q$, $q$Yes, Outgrow lets users create and test variations of their interactive content to compare completion and conversion rates.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Lead generation quizzes$q$, $q$Marketing teams build personality or recommendation quizzes that capture contact details in exchange for a personalized result.$q$, $q$B2B and B2C marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$ROI and savings calculators$q$, $q$Sales and marketing teams create interactive calculators that estimate cost savings or ROI to qualify prospects earlier in the funnel.$q$, $q$SaaS and services companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Agency client campaigns$q$, $q$Marketing agencies build and manage interactive content campaigns across multiple client accounts from one platform.$q$, $q$Digital marketing agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Free Forms and Surveys$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["Forms and surveys only","Up to 1,200 leads per year","Up to 4 content pieces","1 user","Card layout"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Freelancer Limited$q$, $q$$22/month monthly, about $14/month billed annually$q$, $q$Monthly or annual$q$, NULL, $q$["5 content types","Up to 3,000 leads per year","5 content pieces","1 user","Logo and color branding","Standard integrations","Live chat support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Freelancer Pro$q$, $q$$45/month monthly, about $25/month billed annually$q$, $q$Monthly or annual$q$, NULL, $q$["7 content types","Up to 12,000 leads per year","7 content pieces","1 user","Full logic and formula access","Advanced integrations","Live chat support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Essentials$q$, $q$$115/month monthly, about $95/month billed annually$q$, $q$Monthly or annual$q$, NULL, $q$["9 content types","Up to 90,000 leads per year","Unlimited content pieces","3 users","Charts and graphs","48-hour email and live chat support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Business$q$, $q$$720/month monthly, about $600/month billed annually$q$, $q$Monthly or annual$q$, NULL, $q$["All 9 content types","Up to 600,000 leads per year","Unlimited content pieces","10 users","Custom domain hosting","Complete branding control","24-hour priority support"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Fully customizable limits","Built for mid-market, enterprise, and agency needs","Dedicated support"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Outgrow is a marketing platform built around one idea: people engage more with content that responds to them. Instead of a static blog post or landing page, Outgrow lets teams build quizzes, calculators, assessments, polls, contests, and chatbots that ask visitors questions and return a personalized result, such as a product recommendation, a savings estimate, or a qualification score.$q$, $q$The platform is aimed squarely at marketing and growth teams rather than developers. Content is built visually with pre-made templates, and each piece of interactive content doubles as a lead capture form, so the data collected can be synced into a CRM, ad platform, or email tool to power follow-up campaigns and segmentation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the center of Outgrow is a logic and formula engine that lets non-technical users build branching quizzes and multi-variable calculators without writing code, along with a library of industry-specific templates to speed up setup.$q$, $q$Beyond the builder, Outgrow includes lead scoring rules that assign point values to answers, analytics on completion rates and drop-off points, A/B testing of variants, and native integrations with tools such as HubSpot, Mailchimp, Marketo, and Zapier so qualified leads flow directly into existing marketing and sales workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba73b0fc-07ff-4d10-9bbb-1291ae579cf8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Outgrow follows a freemium, tiered-subscription model. A free plan is limited to basic forms and surveys with a capped number of leads per year, while paid Freelancer, Essentials, and Business plans progressively raise the number of supported content types, annual lead volume, seats, and available layouts, and add features like custom domain hosting and priority support.$q$, $q$Annual billing is discounted heavily versus monthly billing on every paid tier, and Outgrow also offers custom Startup plans and an Enterprise and agency tier with negotiated pricing for larger teams that need higher volume or more customization.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Real-time collaborative editor$q$, $q$Markdown-based document editor supporting simultaneous multi-user editing and inline comments.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Nested collections$q$, $q$Organizes documents into hierarchical collections so knowledge bases stay structured as they grow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Full-text search$q$, $q$Instant search across all documents, titles, and content within a workspace.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Version history$q$, $q$Tracks every document revision so past versions can be reviewed or restored.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Self-hosting option$q$, $q$Open-source codebase can be deployed on a team's own infrastructure for free.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$SSO and permissions$q$, $q$Single sign-on plus group- and role-based access controls on Team and Business plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$API and webhooks$q$, $q$Programmatic access to documents and events for building custom integrations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$AI question answering and translation$q$, $q$AI-assisted answers sourced from existing documentation, plus multi-language document translation.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Open-source codebase allows free, fully controlled self-hosting$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Fast, keyboard-driven editor built specifically for engineering and product teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Markdown compatibility makes content portable and developer-friendly$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Bootstrapped, profitable company with a long track record of stability$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Clean, focused feature set compared to broader all-in-one workspace tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Fewer all-in-one features (databases, project management) than tools like Notion$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Self-hosting requires technical setup and ongoing maintenance$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Cloud pricing is per-plan-tier based on team size, which can jump significantly as headcount grows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Smaller integration ecosystem than larger enterprise wiki platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Advanced permission and audit features are reserved for higher-priced plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Is Outline open source?$q$, $q$Yes, the majority of Outline's codebase, including its editor and website, is open source and available on GitHub, allowing teams to self-host it for free.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Can I self-host Outline for free?$q$, $q$Yes, self-hosting the open-source version is free aside from your own infrastructure costs; the hosted cloud version is a separate paid service.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$How much does Outline's hosted plan cost?$q$, $q$Outline's cloud plans start at about $10 per month for the Starter tier, with Team and Business tiers priced higher based on team size and features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$What is Outline best used for?$q$, $q$Outline is best used as an internal team knowledge base for documentation, product specs, meeting notes, and onboarding content, particularly for engineering and product teams.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Does Outline support single sign-on?$q$, $q$Yes, SSO authentication is available starting on the Team plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$How is Outline different from Notion?$q$, $q$Outline is more narrowly focused on documentation and wikis, with a faster markdown-native editor and a self-hostable open-source option, whereas Notion is a broader all-in-one workspace with databases and project tools.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Is there a free trial for Outline's cloud plans?$q$, $q$Yes, all cloud plans include a 30-day free trial.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$What are the main alternatives to Outline?$q$, $q$Common alternatives include Notion, Confluence, GitBook, and Slab.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Engineering documentation$q$, $q$Engineering teams maintain runbooks, architecture docs, and onboarding guides in searchable, version-controlled collections.$q$, $q$Software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Company-wide internal wiki$q$, $q$Organizations centralize policies, meeting notes, and cross-team knowledge in a single searchable workspace.$q$, $q$Startups and mid-size companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Self-hosted knowledge base for data-sensitive teams$q$, $q$Teams with strict data residency or compliance requirements self-host Outline on their own infrastructure instead of using a third-party cloud service.$q$, $q$Regulated or security-conscious organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Self-hosted (open source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source codebase","Deployed on your own infrastructure","No per-seat fees"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Starter$q$, $q$$10/month$q$, $q$Monthly$q$, NULL, $q$["For teams of 1-10 members","Unlimited docs with version history","Real-time collaborative editing","Commenting with @mentions","AI question answering"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Team$q$, $q$$79/month$q$, $q$Monthly$q$, NULL, $q$["For teams of 11-100 members","Everything in Starter","SSO authentication","20+ integrations including Zapier","Templating, groups, and permissions"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Business$q$, $q$$249/month$q$, $q$Monthly$q$, NULL, $q$["For teams of 101-200 members","Everything in Team","API and webhooks","Security audit log","Email support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["For teams larger than 200 users","Custom terms and support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Outline is built specifically as a team knowledge base: a place for internal documentation, engineering runbooks, product specs, onboarding material, and meeting notes to live in organized, searchable collections rather than scattered across chat and shared drives.$q$, $q$The product exists in two forms. Teams can use the official hosted cloud service, or they can self-host the open-source codebase on their own infrastructure for full control over data residency and cost, since the vast majority of Outline's code, including its editor and website, is publicly available.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Documents in Outline are organized into nested collections, edited in a real-time collaborative markdown-based editor with commenting and @mentions, and tracked with full version history so changes can always be reviewed or reverted.$q$, $q$On top of the core editing experience, Outline adds instant full-text search, single sign-on and group-based permissions for larger teams, an API and webhooks for building custom workflows, and AI features such as question answering over existing documentation and multi-language translation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The self-hosted, open-source version of Outline is free to run on a team's own servers, with the only ongoing cost being infrastructure. For teams that prefer not to manage hosting, Outline offers a cloud service billed by team size across Starter, Team, and Business tiers, each unlocking more integrations, permission controls, and support as team size grows.$q$, $q$All cloud plans include a 30-day free trial, and nonprofit or educational organizations can qualify for a discount. Organizations with more than 200 users are directed to a custom Enterprise plan negotiated directly with Outline's sales team.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('28c0a1b2-9008-4c7f-a6b9-e522bb6fafb3', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Multichannel sequences$q$, $q$Combines email, calling, LinkedIn, SMS, and WhatsApp steps into a single automated outreach cadence.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Built-in dialer$q$, $q$Power dialer with automatic voicemail drop, call recording, and conversation transcription.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$AI sequence and email writer$q$, $q$Generates outreach copy and sequence structure using AI assistance.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Website visitor tracking$q$, $q$Identifies and tracks visitors on a company's website for follow-up outreach.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$CRM integrations$q$, $q$Native two-way sync with Salesforce, Microsoft Dynamics 365, and other CRMs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Chrome extension$q$, $q$Prospects and adds contacts directly from LinkedIn and other web pages.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$A/B testing$q$, $q$Tests different sequence variants to optimize reply and conversion rates.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Sales analytics and reporting$q$, $q$Advanced reporting on sequence performance and rep activity on higher-tier plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Free Forever plan makes it accessible to individual reps and very small teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Broad channel coverage including WhatsApp, which is uncommon among competitors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Built-in dialer and conversation intelligence reduce the need for separate tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Priced lower than many enterprise sales engagement platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Backed by continued investment following its 2025 acquisition by JungleWorks$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Advanced calling and reporting features require the top Enterprise tier$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Many capabilities are gated behind paid add-ons rather than included in base plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Smaller ecosystem and brand recognition than category leaders like Outreach or Salesloft$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Per-user annual pricing can add up quickly for larger sales teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Recent acquisition introduces some uncertainty around long-term product direction$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$What is Outplay used for?$q$, $q$Outplay is used by sales teams to automate multichannel outreach sequences across email, calling, LinkedIn, SMS, and WhatsApp, combined with a built-in dialer and CRM sync.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Does Outplay have a free plan?$q$, $q$Yes, Outplay offers a Free Forever plan with a limited number of active prospects and basic multichannel outreach features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$How much does Outplay cost?$q$, $q$Paid plans start at $39 per month for Starter and scale up to $89 and $139 per user per month for Growth and Enterprise, all billed annually with a 7-day free trial.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Who owns Outplay?$q$, $q$Outplay was acquired by JungleWorks in March 2025, though co-founders Laxman and Ram Papineni continue to lead the company's day-to-day operations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Does Outplay integrate with Salesforce?$q$, $q$Yes, Outplay offers native integration with Salesforce as well as Microsoft Dynamics 365 on its Growth and Enterprise plans.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Who is Outplay best suited for?$q$, $q$Outplay is best suited for small and mid-market B2B sales teams looking for an affordable, all-in-one alternative to larger sales engagement platforms.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$What are the main alternatives to Outplay?$q$, $q$Common alternatives include Outreach, Salesloft, Apollo.io, and Klenty.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Does Outplay support LinkedIn outreach?$q$, $q$Yes, Outplay includes LinkedIn automation as part of its multichannel sequences, available as a power-up add-on on some plans.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Multichannel outbound prospecting$q$, $q$SDR teams combine email, calls, and LinkedIn touches into unified sequences to reach more prospects with less manual effort.$q$, $q$Sales development representatives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Inside sales calling programs$q$, $q$Sales teams use the built-in power dialer and call recording to run high-volume calling campaigns with coaching insights.$q$, $q$Inside sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Small business lead outreach$q$, $q$Individual founders or small sales teams use the free plan to run basic outreach without additional software spend.$q$, $q$Startups and small businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Free Forever$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["Up to 2,000 active prospects per month","5,000 prospect storage","2 mailboxes","Multichannel outreach including WhatsApp","Basic dialer","AI mail writer"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Starter$q$, $q$$39/month$q$, $q$Annual$q$, NULL, $q$["5,000+ active prospects","20,000 prospect storage","5 mailboxes","Unlimited emails","1 user","AI sequence writer","CRM integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Growth$q$, $q$$89/user/month$q$, $q$Annual$q$, NULL, $q$["Unlimited prospects","5 mailboxes per user","Multichannel outreach","Salesforce and Dynamics 365 integration","Website tracking","Chrome extension"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$Enterprise$q$, $q$$139/user/month$q$, $q$Annual$q$, NULL, $q$["Unlimited prospects","15 mailboxes per user","Power dialer with auto voicemail drop","Slack integration","SSO (Okta and SAML)","Dedicated success manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Outplay is a sales engagement platform designed to let sales reps run coordinated outreach across multiple channels, including email, phone calls, LinkedIn, SMS, and WhatsApp, from a single sequence rather than juggling separate tools for each channel.$q$, $q$The platform combines sequence automation with a built-in dialer, conversation recording and transcription, and website visitor tracking, aiming to give small and mid-market sales teams many of the same capabilities as larger, more expensive sales engagement suites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core to Outplay is its multichannel sequence builder, which lets reps combine email, calls, LinkedIn touches, SMS, and WhatsApp steps into a single automated cadence, supported by an AI sequence and email writer and a library of pre-built templates.$q$, $q$Beyond sequencing, Outplay includes a power dialer with automatic voicemail drop and call recording, conversation intelligence with transcription, a Chrome extension for prospecting, and native CRM integrations with platforms like Salesforce and Microsoft Dynamics 365, plus Slack and SSO on higher tiers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('909a6d6a-53a7-4fd9-8771-f0bad14e7055', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Outplay offers a Free Forever plan with a capped number of active prospects and basic multichannel features, making it accessible to very small teams or individual reps at no cost.$q$, $q$Paid plans, billed per user annually, scale from Starter through Growth to Enterprise, each raising mailbox limits, unlocking more channels and CRM integrations, and adding features like advanced reporting, SSO, and a dedicated success manager. Optional add-ons, called power-ups, cover things like email warm-up, additional calling minutes, and AI SDR functionality.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Multichannel sequences$q$, $q$Automates outbound email, calling, and other touches into coordinated prospecting cadences.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$AI sales agents$q$, $q$Agents such as Outreach Omni and a Meeting Prep Agent automate research, briefings, and account actions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Deal inspection$q$, $q$Flags at-risk deals and surfaces stakeholder engagement data for active opportunities.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$AI-assisted forecasting$q$, $q$Generates pipeline and revenue forecasts with scenario planning and multi-currency support on higher tiers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Conversation intelligence$q$, $q$Records and analyzes sales calls and meetings for coaching and buyer insight.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Agent Studio$q$, $q$Visual workflow builder for configuring custom AI agent automations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Integrated dialer$q$, $q$Built-in calling with post-call summarization and logging.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$CRM integration$q$, $q$Two-way sync with Salesforce and other major CRMs to keep pipeline data current.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Deep, enterprise-grade feature set spanning prospecting, deal management, and forecasting$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Heavy recent investment in AI agents for research, coaching, and meeting prep$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Strong track record and category leadership backed by significant funding and scale$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Integrated conversation intelligence reduces the need for a separate coaching tool$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Robust reporting and forecasting suited to complex, multi-team sales organizations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Pricing is entirely custom and not disclosed publicly, complicating budget comparisons$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Platform complexity and breadth can be overkill for small or simple sales teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Implementation and onboarding typically require more time than lighter-weight competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Cost is generally higher than mid-market alternatives like Outplay or Apollo.io$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Recent rebrand and product restructuring may require relearning for existing customers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$What is Outreach used for?$q$, $q$Outreach is used by sales organizations to automate prospecting sequences, manage and inspect deals, forecast revenue, and coach reps using AI-assisted conversation intelligence.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$How much does Outreach cost?$q$, $q$Outreach does not publish pricing publicly; prospective customers must request a demo and receive a custom quote based on their needs and team size.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Is Outreach the same company as Outreach.io?$q$, $q$Yes, Outreach rebranded its website from outreach.io to outreach.ai around 2025-2026 to reflect its focus on agentic AI, but it remains the same company and product line.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Who founded Outreach?$q$, $q$Outreach was founded in 2014 by Wes Hather, Gordon Hempton, Manny Medina, Belinda Prince, and Andrew Kinzer.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Where is Outreach headquartered?$q$, $q$Outreach is headquartered in Seattle, Washington, with additional offices in Atlanta, New York, and San Francisco.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$What are Outreach's pricing tiers called?$q$, $q$Outreach's current packaging is organized into three tiers: Amplify Core, Amplify Plus, and Amplify Pro, each adding more advanced forecasting, coaching, and deal-management features.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Who are Outreach's main competitors?$q$, $q$Outreach's main competitors include Salesloft, HubSpot Sales Hub, Apollo.io, and Outplay.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Is Outreach suitable for small sales teams?$q$, $q$Outreach is generally built for mid-market and enterprise sales organizations; smaller teams may find lighter-weight, self-serve platforms more cost-effective.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Enterprise outbound prospecting$q$, $q$Large sales development teams run coordinated multichannel outreach sequences at scale with centralized reporting.$q$, $q$Enterprise sales development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Deal and pipeline management$q$, $q$Sales managers use deal inspection and AI forecasting to identify at-risk opportunities and improve forecast accuracy.$q$, $q$Sales managers and revenue operations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Rep coaching and enablement$q$, $q$Sales enablement teams use conversation intelligence and AI coaching to review calls and improve rep performance.$q$, $q$Sales enablement and training teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Amplify Core$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["AI agents","Integrated dialer","Sequences and triggers","Post-call summarization","Smart data enrichment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Amplify Plus$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Everything in Amplify Core","Real-time call transcription","AI coaching","Deal Agent and deal health scoring","Pipeline management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$Amplify Pro$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Everything in Amplify Plus","Commit-style forecasting","Scenario planning","AI revenue projection","Multi-currency support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Outreach is one of the original category leaders in sales engagement software, built to help sales teams automate outbound prospecting sequences across email, phone, and other channels while giving managers visibility into pipeline and rep performance.$q$, $q$Over its history the platform has grown from a sequence-automation tool into a broader revenue execution suite covering deal management, forecasting, and coaching, and it has more recently repositioned itself around AI agents that can research prospects, flag at-risk deals, and prepare reps for meetings automatically.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Outreach's foundation is multichannel sequence automation combined with an integrated dialer and email tracking, layered with AI agents that handle tasks like prospect research, account stakeholder mapping, and meeting preparation.$q$, $q$On the management side, Outreach provides deal inspection and risk flagging, AI-assisted forecasting and scenario planning, conversation intelligence for coaching reps from call and meeting recordings, and workflow automation tools such as Agent Studio for configuring custom AI-driven processes.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7afd1993-2c5f-430d-bd16-ce044308f9b1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Outreach does not publish list pricing. The company sells through a direct sales process, with prospective customers requesting a demo and receiving a custom quote based on team size, modules, and contract terms.$q$, $q$Its current packaging is organized around three tiers, called Amplify Core, Amplify Plus, and Amplify Pro, which progressively add features like real-time call transcription, AI coaching, deal health scoring, and multi-currency forecasting as customers move up the tier structure.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Virtual private servers$q$, $q$NVMe SSD-backed VPS plans with guaranteed bandwidth and built-in anti-DDoS protection.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Bare-metal dedicated servers$q$, $q$Dedicated physical servers with configurable hardware for performance-sensitive workloads.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Public cloud$q$, $q$OpenStack-based compute, storage, and managed database services billed on usage.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Managed Kubernetes$q$, $q$Fully managed Kubernetes clusters for containerized application deployment.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Private cloud$q$, $q$VMware-based private cloud infrastructure for enterprise workloads requiring isolation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Object and block storage$q$, $q$Scalable storage services for backups, archives, and application data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Web hosting and domains$q$, $q$Shared web hosting, email hosting, and domain registration for smaller sites and businesses.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Anti-DDoS protection$q$, $q$Network-level DDoS mitigation included by default across most infrastructure products.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Transparent, published pricing for VPS and dedicated servers well below typical hyperscaler rates$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$European data sovereignty appeals to GDPR-conscious and public sector customers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Vertically integrated infrastructure (own data centers, network, and hardware) supports cost efficiency$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Broad global data center footprint despite being a European-first provider$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Wide product range covering everything from cheap VPS to enterprise private cloud$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Smaller managed-service and marketplace ecosystem compared to AWS, Azure, or Google Cloud$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Documentation and support quality can be less polished than the largest US hyperscalers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Historical high-profile data center incidents (including a major fire) have raised reliability concerns for some customers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Enterprise and public cloud pricing requires custom quotes rather than fully transparent self-serve rates$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Interface and console are viewed by some users as less refined than competitors like DigitalOcean$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$What is OVHcloud used for?$q$, $q$OVHcloud is used to run virtual private servers, dedicated servers, public and private cloud workloads, storage, and web hosting for individuals, businesses, and enterprises.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Where is OVHcloud headquartered?$q$, $q$OVHcloud is headquartered in Roubaix, France, and was founded there in 1999 by Octave Klaba.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$How much does OVHcloud cost?$q$, $q$Entry-level VPS plans start at roughly $4-6 per month, while dedicated servers, public cloud, and enterprise services are billed on usage-based or custom-quoted pricing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Is OVHcloud a European alternative to AWS?$q$, $q$Yes, OVHcloud is widely positioned as Europe's largest independent cloud provider and is often chosen as a European alternative to AWS, Google Cloud, and Microsoft Azure for data sovereignty and cost reasons.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Does OVHcloud offer managed Kubernetes?$q$, $q$Yes, OVHcloud offers a fully managed Kubernetes service as part of its public cloud portfolio.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Is DDoS protection included with OVHcloud servers?$q$, $q$Yes, anti-DDoS protection is included by default on most OVHcloud VPS and dedicated server products.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Who are OVHcloud's main competitors?$q$, $q$OVHcloud's main competitors include Hetzner, DigitalOcean, and Scaleway, as well as AWS, Google Cloud, and Microsoft Azure.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$How many data centers does OVHcloud operate?$q$, $q$OVHcloud operates dozens of data centers across multiple continents as part of its global infrastructure footprint.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Affordable VPS hosting for developers$q$, $q$Individual developers and small businesses run websites, apps, and side projects on low-cost VPS plans.$q$, $q$Developers and small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$GDPR-aligned enterprise cloud$q$, $q$European enterprises and public sector organizations run workloads on OVHcloud for data sovereignty and compliance reasons.$q$, $q$European enterprises and public sector$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$High-performance dedicated hosting$q$, $q$Companies running performance-sensitive applications such as gaming servers or databases rent bare-metal dedicated servers.$q$, $q$Performance-focused technical teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$VPS$q$, $q$From about $4-6/month$q$, $q$Monthly or long-term$q$, NULL, $q$["NVMe SSD storage","Guaranteed bandwidth","Free IPv4 and IPv6","Built-in anti-DDoS protection"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Dedicated Servers$q$, $q$Custom, varies by hardware configuration$q$, $q$Monthly$q$, NULL, $q$["Configurable physical hardware","High performance for demanding workloads","Anti-DDoS protection included"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Public Cloud$q$, $q$Usage-based$q$, $q$Pay-as-you-go$q$, NULL, $q$["OpenStack-based compute and storage","Managed Kubernetes and databases","Pay only for resources consumed"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$Enterprise and Private Cloud$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["VMware-based private cloud","Dedicated account management","Custom SLAs and compliance support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OVHcloud is a French cloud computing and hosting company that has grown from a small regional web host into Europe's largest independent cloud infrastructure provider, built on data centers, networking, and even server hardware that the company designs and operates itself.$q$, $q$The company serves everyone from individual developers renting a low-cost VPS to large enterprises and public sector organizations that choose OVHcloud specifically for European data sovereignty and independence from the major US cloud hyperscalers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OVHcloud's product line spans virtual private servers, bare-metal dedicated servers, OpenStack-based public cloud, VMware-based private cloud, managed Kubernetes, object and block storage, and domain and web hosting services, all backed by built-in anti-DDoS protection.$q$, $q$Because OVHcloud owns and operates its own data centers and network backbone rather than reselling infrastructure, it is able to publish transparent, relatively low self-serve pricing for standardized products while also offering custom-quoted enterprise and public cloud contracts for larger deployments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0290e212-4db0-41b8-bc28-0411526ba848', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Entry-level products such as VPS plans have clearly published monthly prices, generally ranging from around $4 to $45 per month depending on compute, memory, and storage specifications, with volume and long-term billing discounts available.$q$, $q$Public cloud compute, storage, and managed services are typically billed on a usage or consumption basis similar to other major cloud providers, while large enterprise contracts, private cloud deployments, and dedicated infrastructure at scale are generally quoted individually by OVHcloud's sales team.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$CPE-to-CVE matching$q$, $q$Maps dependency evidence to CPE identifiers and cross-references the NVD to surface known CVEs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Multi-ecosystem scanning$q$, $q$Covers Java and .NET natively, with additional checks for JavaScript, Ruby, and other ecosystems via integrated data sources.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Build tool plugins$q$, $q$Available as plugins for Maven, Gradle, and Ant to run scans as part of the normal build process.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$CI/CD integration$q$, $q$Integrates with Jenkins, GitHub Actions, and Azure DevOps for automated scanning in pipelines.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$CVSS severity scoring$q$, $q$Reports include CVSS scores to help teams prioritize which vulnerabilities to remediate first.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Offline/local scanning$q$, $q$Runs entirely within a team's own infrastructure without sending code to a third-party service.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Suppression files$q$, $q$Lets teams suppress known false positives so they do not repeatedly clutter scan reports.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Completely free and open source with no usage limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Runs locally or in CI without sending proprietary code to a third party$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Long track record as one of the original SCA tools in the OWASP ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Integrates directly into common build tools like Maven and Gradle$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Backed by the well-established NVD vulnerability database$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$CPE-based matching can produce false positives that require manual suppression$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$No official hosted dashboard or vulnerability management UI out of the box$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Coverage is strongest for Java and .NET, with less mature support for some other ecosystems$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$No commercial support contract available directly from the project$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Requires NVD data feed updates that can be slow or rate-limited without an API key$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$What is OWASP Dependency-Check used for?$q$, $q$It is used to scan a project's third-party dependencies and identify any that have publicly disclosed, known vulnerabilities (CVEs).$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Is OWASP Dependency-Check free?$q$, $q$Yes, it is completely free and open source under the Apache License 2.0.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$How does Dependency-Check identify vulnerabilities?$q$, $q$It gathers evidence about each dependency, maps it to Common Platform Enumeration identifiers, and cross-references the National Vulnerability Database to find matching CVE records.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$What languages and ecosystems does it support?$q$, $q$It has strongest native support for Java and .NET, with additional checks for JavaScript, Ruby, and other ecosystems via integrated data sources like the NPM Audit API and Bundler Audit.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$How is Dependency-Check different from OWASP ZAP?$q$, $q$Dependency-Check is a software composition analysis tool that scans dependencies for known vulnerable libraries, while OWASP ZAP is a dynamic application security testing tool that actively scans and attacks a running web application.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Can Dependency-Check run in a CI/CD pipeline?$q$, $q$Yes, it integrates with Jenkins, GitHub Actions, and Azure DevOps, as well as Maven, Gradle, and Ant plugins for build-time scanning.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$What are the alternatives to OWASP Dependency-Check?$q$, $q$Alternatives and complementary tools include OWASP Dependency-Track, Snyk, Mend (formerly WhiteSource), and GitHub Dependabot.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Who maintains OWASP Dependency-Check?$q$, $q$It was created by Jeremy Long and is maintained by a community of volunteer contributors under the OWASP Foundation.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$CI/CD vulnerability gating$q$, $q$DevSecOps teams run Dependency-Check as a build step to fail builds when high-severity known-vulnerable dependencies are detected.$q$, $q$DevSecOps and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Open-source license and risk audits$q$, $q$Security teams periodically scan codebases to inventory dependencies and known vulnerabilities for compliance reporting.$q$, $q$Application security teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Individual developer dependency checks$q$, $q$Developers run local scans before committing code to catch known-vulnerable libraries early.$q$, $q$Individual software developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full CLI tool and build plugins","CPE-to-CVE vulnerability matching","CI/CD integrations","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OWASP Dependency-Check is a software composition analysis tool built to answer a simple but important question: does this project use any open-source libraries with publicly known security vulnerabilities?$q$, $q$Rather than analyzing an application's own source code, Dependency-Check inspects the third-party dependencies pulled in through package managers and build tools, matching them against public vulnerability databases so teams can catch known-vulnerable components before they ship.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The tool identifies dependencies and gathers evidence about them, then attempts to map that evidence to Common Platform Enumeration identifiers so it can cross-reference the National Vulnerability Database for matching CVE records, generating a report with CVE IDs, CVSS severity scores, and links to advisories.$q$, $q$It runs as a standalone command-line utility or via build-tool plugins for Maven, Gradle, and Ant, and integrates into CI/CD pipelines including Jenkins, GitHub Actions, and Azure DevOps, with additional ecosystem-specific checks pulled from sources like the NPM Audit API, OSS Index, RetireJS, and Bundler Audit.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4e30e978-262d-4a83-b746-96ea2a1f37ae', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dependency-Check is entirely free and open source under the Apache License 2.0, with no paid tiers, license fees, or usage limits since it runs locally or in a team's own CI infrastructure.$q$, $q$Because it is community-maintained rather than sold as a product, there is no vendor support contract available directly through the project; teams that want commercial support and a hosted dashboard experience typically pair it with, or migrate to, tools like OWASP Dependency-Track or a commercial SCA platform.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Active and passive scanning$q$, $q$Automatically probes applications with attack payloads while also passively analyzing observed traffic for issues.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Intercepting proxy$q$, $q$Sits between client and server to inspect, modify, and replay web traffic for manual testing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Fuzzing$q$, $q$Sends large sets of crafted inputs to application parameters to uncover edge-case vulnerabilities.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Automation framework$q$, $q$Scripts and schedules ZAP scans for integration into CI/CD pipelines.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Add-on marketplace$q$, $q$Community-built add-ons extend scan rules, authentication support, and reporting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$API and application scanning$q$, $q$Scans traditional web applications as well as REST and SOAP APIs for vulnerabilities.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Authentication handling$q$, $q$Supports scanning behind login forms and various authentication schemes.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Completely free and open source with no feature restrictions$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Widely regarded as the leading open-source alternative to commercial DAST scanners like Burp Suite$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Backed by an active community and, since 2024, Checkmarx sponsorship for continued development$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Strong automation framework for embedding scans into CI/CD pipelines$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Extensible via a large marketplace of community add-ons$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Steeper learning curve than some commercial scanners for advanced manual testing workflows$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Active scans can generate false positives that require manual triage$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Project governance changes (leaving OWASP, joining Checkmarx) have created some confusion about its status$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$User interface is less polished than premium commercial alternatives$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Scanning complex, heavily JavaScript-driven single-page applications can require additional configuration$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$What is OWASP ZAP used for?$q$, $q$OWASP ZAP is used to find security vulnerabilities in running web applications and APIs by actively and passively scanning traffic, similar to how a penetration tester would probe an application.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Is OWASP ZAP free?$q$, $q$Yes, ZAP is completely free and open source under the Apache License 2.0, with no paid tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Is OWASP ZAP still an OWASP project?$q$, $q$ZAP left the OWASP Foundation in 2023 to join the Linux Foundation's Software Security Project, and in 2024 its core team joined Checkmarx, with the project now branded ZAP by Checkmarx while remaining free and open source.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$How is OWASP ZAP different from OWASP Dependency-Check?$q$, $q$ZAP is a dynamic application security testing tool that actively scans a running web application for vulnerabilities, while Dependency-Check is a software composition analysis tool that scans a project's dependencies for known vulnerable libraries.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Who created OWASP ZAP?$q$, $q$ZAP was founded in 2010 by Simon Bennetts, forked from the Paros proxy originally developed by Chinotec Technologies.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Can OWASP ZAP be automated in a CI/CD pipeline?$q$, $q$Yes, ZAP includes an automation framework specifically designed to script and schedule scans as part of CI/CD workflows.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$What are the main alternatives to OWASP ZAP?$q$, $q$Common alternatives include Burp Suite, Acunetix, Invicti (formerly Netsparker), and Nikto.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Does OWASP ZAP scan APIs as well as web pages?$q$, $q$Yes, ZAP can scan REST and SOAP APIs in addition to traditional web applications.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Automated DAST in CI/CD$q$, $q$Development teams run ZAP scans automatically against staging environments on every build to catch vulnerabilities before release.$q$, $q$DevSecOps and engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Manual penetration testing$q$, $q$Security professionals use ZAP's proxy, fuzzer, and manual testing tools to perform in-depth application penetration tests.$q$, $q$Penetration testers and security consultants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$API security testing$q$, $q$Teams scan REST and SOAP APIs for injection flaws, authentication weaknesses, and misconfigurations.$q$, $q$Application security engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Active and passive scanning","Intercepting proxy and fuzzer","Automation framework","Community add-on marketplace"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OWASP ZAP is a dynamic application security testing tool: instead of reading source code or dependency manifests, it actively interacts with a running web application or API to find exploitable vulnerabilities the way an attacker would.$q$, $q$It works as an intercepting proxy, sitting between a browser or test client and the target application, which lets it both passively observe every request and response and actively send crafted, potentially malicious inputs to probe for weaknesses like injection flaws and cross-site scripting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ZAP combines an automated scanner (both passive, which just observes traffic, and active, which sends attack payloads) with manual testing tools such as a traffic interceptor, request replay, and fuzzer, making it useful for both automated pipeline scans and hands-on penetration testing.$q$, $q$An automation framework lets teams script and schedule ZAP scans as part of CI/CD, while a marketplace of community-contributed add-ons extends the core tool with additional scan rules, authentication handlers, and reporting formats.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26fa7763-662c-4590-abb7-062fe17b309e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ZAP is entirely free and open source under the Apache License 2.0, with no paid tiers or feature gating; every capability, from active scanning to the automation framework, is available at no cost.$q$, $q$Since its core team joined Checkmarx in 2024 as ZAP by Checkmarx, the project has continued as an independently governed open-source effort backed by Checkmarx sponsorship rather than being converted into a commercial product, so pricing and licensing terms for end users have not changed.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Self-hosted streaming server$q$, $q$Runs entirely on infrastructure the user controls, with no dependency on a third-party streaming platform.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$OBS-compatible ingest$q$, $q$Accepts standard RTMP streams from broadcasting software such as OBS Studio.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Built-in web chat$q$, $q$Customizable live chat with support for custom emotes and chatbot integrations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$ActivityPub federation$q$, $q$Lets streams and updates be discovered and followed from Mastodon and other Fediverse platforms.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Video transcoding$q$, $q$Automatically transcodes incoming streams into multiple quality levels for viewers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Embeddable player$q$, $q$Streams can be embedded on external websites via a standard video player.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Open-source and self-owned$q$, $q$Full control over data, moderation, and monetization since there is no third-party platform involved.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Completely free, open-source software with no subscription costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Full ownership and control over content, chat, and audience data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$No platform algorithm, ad policies, or content moderation rules imposed by a third party$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$ActivityPub support enables discovery through the Fediverse without a centralized platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Simple Docker-based setup makes self-hosting accessible to non-experts with basic server skills$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Requires the user to provide and pay for their own server and bandwidth$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$No built-in audience discovery comparable to Twitch's or YouTube's recommendation algorithms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Self-hosting means the user is responsible for uptime, scaling, and server security$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Smaller ecosystem of extensions and integrations compared to major commercial platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$No native monetization tools like subscriptions or virtual currency built into the platform$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$What is Owncast used for?$q$, $q$Owncast is used to run a self-hosted live video streaming and chat server, giving creators an independent alternative to platforms like Twitch or YouTube Live.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Is Owncast free?$q$, $q$Yes, Owncast is completely free and open source under the MIT License; the only cost is the server or hosting infrastructure the user runs it on.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Who created Owncast?$q$, $q$Owncast was created by developer Gabe Kangas, who remains its primary maintainer alongside community contributors.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$What streaming software works with Owncast?$q$, $q$Owncast accepts standard RTMP streams, so it works with common broadcasting software such as OBS Studio.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Does Owncast support chat?$q$, $q$Yes, Owncast includes a built-in, customizable web chat with support for custom emotes and chatbot integrations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Can Owncast streams be found on Mastodon?$q$, $q$Yes, Owncast supports ActivityPub federation, allowing streams and updates to be followed from Mastodon and other Fediverse platforms.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$What are the alternatives to Owncast?$q$, $q$Alternatives include PeerTube for self-hosted video, as well as centralized commercial platforms like Twitch, YouTube Live, and Kick.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$How is Owncast funded if it is free?$q$, $q$The project is funded through donations via Open Collective, sponsorships from companies like Fastly and DigitalOcean, and merchandise sales.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Independent musician live streams$q$, $q$Musicians and performers run their own branded live streaming site instead of depending on a mainstream platform's rules and algorithm.$q$, $q$Independent musicians and performers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Community and hobbyist streaming$q$, $q$Hobbyist creators and small communities self-host a private or public streaming server for events, gaming, or shows.$q$, $q$Hobbyist streamers and online communities$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Privacy-focused organizational streaming$q$, $q$Organizations that need full control over stream data and moderation self-host Owncast instead of using a third-party platform.$q$, $q$Privacy-conscious organizations and creators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$Self-hosted (open source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full streaming server software","Built-in chat","ActivityPub federation","MIT licensed, no usage limits"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Owncast gives individual creators and communities the ability to run their own live streaming service, rather than publishing exclusively through a centralized platform like Twitch. It handles video ingest, transcoding, delivery, and chat, so a single server is enough to run a fully functional streaming site.$q$, $q$The project was created by developer Gabe Kangas and grew out of a desire to give creators, especially musicians during the pandemic, more control and ownership over their live streams and audience relationships than mainstream platforms typically allow.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Broadcasters connect to their Owncast server using standard software such as OBS Studio, just as they would with any commercial streaming platform, and Owncast handles transcoding the stream into multiple qualities for viewers.$q$, $q$Alongside video, Owncast includes a built-in, customizable web chat with support for custom emotes and chatbots, an embeddable video player, and ActivityPub-based federation that lets a self-hosted stream be discovered and followed from Mastodon and other Fediverse services.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Owncast itself is completely free and open source under the MIT License, with no subscription fees, feature gating, or usage limits imposed by the software.$q$, $q$The only real cost to running Owncast is infrastructure: a server or cloud VPS with enough bandwidth and CPU to handle video transcoding and viewer traffic. The project itself is funded through donations, sponsorships from companies like Fastly and DigitalOcean, and merchandise sales rather than by charging users.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a8c86fff-3023-43da-8e2f-7a64b9b6fba4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
